class Solution {
    public int findBestValue(int[] arr, int target) {
        Arrays.sort(arr);
        int n = arr.length;
        long sum = 0;
        for (int num : arr) {
            sum += num;
        }
        int left = 1, right = 100000;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            long newSum = sum - (long) arr[n - 1] * (n - 1) + (long) mid * (n - 1);
            if (Math.abs(newSum - target) < Math.abs(sum - target)) {
                sum = newSum;
            }
            if (newSum < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return left - 1;
    }
}
